{"code":"import os, glob, json
root=os.path.expanduser('~/.zeroclaw/workspace/company-wiki/raw')
source_dirs=['slack','trello','github','notion']
for src in source_dirs:
    run_dir=os.path.join(root,src,'runs')
    files=sorted(glob.glob(os.path.join(run_dir,'manifest-*.json')))
    latest=files[-1]
    prev=files[-2] if len(files)>=2 else None
    def load(p):
        with open(p) as f: return json.load(f)
    lj=load(latest)
    pj=load(prev) if prev else None
    print(f'===== {src.upper()} =====')
    for label,j in [('latest',lj),('previous',pj)]:
        if not j: continue
        keys=['created_at','source','status','created_count','deduped_count','error_count','warning_count']
        print(label, {k:j.get(k) for k in keys if k in j})
        # source-specific glimpses
        for k in ['archive_mode','history_summary','repo_count','repos_visible','board_count','team_count','workspace_summary','catalog_summary','progress']:
            if k in j:
                print(label, k, j[k])
        if src=='github':
            # infer recent push leaderboard if repo summaries exists
            rs=j.get('repo_summaries') or j.get('repos') or []
            if isinstance(rs,list):
                top=[]
                for r in rs[:10]:
                    top.append({kk:r.get(kk) for kk in ['name','pushedAt','isPrivate','isArchived','defaultBranchRefName'] if isinstance(r,dict)})
                print(label,'repo_samples',top)
        if src=='trello':
            bs=j.get('boards') or []
            if isinstance(bs,list):
                top=[]
                for b in bs:
                    if isinstance(b,dict):
                        top.append({kk:b.get(kk) for kk in ['id','name','dateLastActivity','closed','members_count','cards_count']})
                print(label,'boards',top)
        if src=='notion':
            ds=j.get('data_sources') or j.get('data_source_summaries') or []
            if isinstance(ds,list):
                top=[]
                for d in ds[:10]:
                    top.append({kk:d.get(kk) for kk in ['title','row_count','id','parent_type'] if isinstance(d,dict)})
                print(label,'data_sources',top)
        if src=='slack':
            print(label,'keys',sorted(j.keys()))
    print()"}

