{"code":"import os, json, glob
from datetime import datetime
base=os.path.expanduser('~/.zeroclaw/workspace/company-wiki/raw/notion/items')
TARGETS={
 'Action Items':'1b549045-5415-80db-844d-000bfda903e2',
 'Todo':'f3f4cb81-965d-4f30-952f-a7903737d6ad',
 'Sentry issue':'cfcc6420-eed5-4478-bac8-b731f1ee112d',
 'slow api':'3e9a1c1d-c66f-49c7-95dd-2b823bd684b3',
 'PRD':'1af49045-5415-8011-b3eb-000bd4d7f61b',
 '회의록':'a0e96802-dc9c-468a-b04c-b51bc1adb1db',
}

def prop_value(p):
    if not isinstance(p,dict): return None
    t=p.get('type')
    if t=='title':
        return ''.join(x.get('plain_text','') for x in p.get('title',[])).strip()
    if t=='rich_text':
        return ''.join(x.get('plain_text','') for x in p.get('rich_text',[])).strip()
    if t=='select':
        s=p.get('select'); return s.get('name') if s else None
    if t=='multi_select':
        return [x.get('name') for x in p.get('multi_select',[])]
    if t=='status':
        s=p.get('status'); return s.get('name') if s else None
    if t=='date':
        d=p.get('date'); return d.get('start') if d else None
    if t=='people':
        return [x.get('name') or x.get('id') for x in p.get('people',[])]
    if t=='checkbox':
        return p.get('checkbox')
    if t=='number':
        return p.get('number')
    if t=='url':
        return p.get('url')
    if t=='email':
        return p.get('email')
    if t=='phone_number':
        return p.get('phone_number')
    if t=='relation':
        return len(p.get('relation',[]))
    return None

# gather query files by data_source_id
summary={}
for title, dsid in TARGETS.items():
    rows=[]
    latest_fetch=None
    files=[]
    for p in glob.glob(os.path.join(base,'*.json')):
        try:
            with open(p) as f: d=json.load(f)
        except Exception:
            continue
        if d.get('payload_kind')!='data_source_query':
            continue
        payload=d.get('payload',{})
        if payload.get('data_source_id')!=dsid:
            continue
        files.append((payload.get('fetched_at'),p,payload.get('row_count')))
        fa=payload.get('fetched_at')
        if fa and (latest_fetch is None or fa>latest_fetch): latest_fetch=fa
        for r in payload.get('results',[]):
            props=r.get('properties',{})
            title_val=None
            flat={}
            for k,v in props.items():
                flat[k]=prop_value(v)
                if k in ('이름','Name','title') and flat[k]: title_val=flat[k]
            if not title_val:
                # first title property fallback
                for k,v in props.items():
                    if isinstance(v,dict) and v.get('type')=='title':
                        title_val=prop_value(v); break
            rows.append({
                'id': r.get('id'),
                'title': title_val,
                'created_time': r.get('created_time'),
                'last_edited_time': r.get('last_edited_time'),
                'url': r.get('url'),
                'props': flat,
            })
    # dedupe by id keeping latest edited record
    ded={}
    for row in rows:
        rid=row['id']
        if rid not in ded or (row.get('last_edited_time') or '')>(ded[rid].get('last_edited_time') or ''):
            ded[rid]=row
    ded_rows=list(ded.values())
    ded_rows.sort(key=lambda x:(x.get('last_edited_time') or '', x.get('created_time') or ''), reverse=True)
    summary[title]={
        'data_source_id': dsid,
        'query_file_count': len(files),
        'latest_fetch': latest_fetch,
        'row_count_unique': len(ded_rows),
        'top_rows': ded_rows[:10],
        'files': sorted(files, reverse=True)[:5],
    }
print(json.dumps(summary, ensure_ascii=False, indent=2))"}

