def load(name):
    with open(os.path.join(base,name)) as f: d=json.load(f)
    payload=d.get('payload',d)
    repos=payload if isinstance(payload,list) else payload.get('repos',[])
    return {r['name']:r for r in repos}
L=load(latest); P=load(prev)
changes=[]
for name,r in L.items():
    p=P.get(name,{})
    fields=[]
    for k in ['pushedAt','updatedAt','isArchived','isPrivate','nameWithOwner']:
        if r.get(k)!=p.get(k):
            fields.append((k,p.get(k),r.get(k)))
    if fields:
        changes.append((name,fields))
print(json.dumps(changes[:20],ensure_ascii=False,indent=2))"}

